const seed=$node.Webhook.json.body.seed_keyword;
const letters=['ا','ب','پ','ت','ج','چ','خ','د','ر','ز','س','ش','ف','ق','ک','گ','ل','م','ن','و','ه','ی'];
const mods=['بهترین','خرید','قیمت','آموزش','چیست','چگونه','مقایسه','ارزان'];
const qs=[];
letters.forEach(l=>qs.push({q:seed+' '+l}));
mods.forEach(m=>qs.push({q:m+' '+seed}));
return qs.map(item=>({json:item}));

const cheerio=require('cheerio');
const html=$input.first().json.body||'';
const $=cheerio.load(html);
const related=[];const questions=[];
$('a').each(function(){const h=$(this).attr('href')||'';const t=$(this).text().trim();if(h.includes('/search?q=')&&t.length>3&&/[\u0600-\u06FF]/.test(t))related.push(t);});
$('[data-q]').each(function(){const q=$(this).attr('data-q');if(q)questions.push(q);});
return[{json:{related:[...new Set(related)].slice(0,15),questions:[...new Set(questions)].slice(0,10)}}];

const ZWNJ='\u200C';
const seed=$node.Webhook.json.body.seed_keyword;
const discId=$node.Webhook.json.body.discovery_id;
const cbUrl=$node.Webhook.json.body.callback_url;
let base=[];
try{const r=$node['Suggest Base'].json;base=Array.isArray(r)?r[1]||[]:(r.body?JSON.parse(r.body)[1]||'[]':[]);}catch(e){}
const expanded=[];
try{const items=$items('Suggest Expanded');items.forEach(item=>{try{const d=item.json;const arr=Array.isArray(d)?d[1]||[]:(d.body?JSON.parse(d.body)[1]||[]:[]);arr.forEach(s=>{if(!expanded.includes(s))expanded.push(s);});}catch(e){}});}catch(e){}
const rel=($node['Extract Related'].json||{}).related||[];
const paa=($node['Extract Related'].json||{}).questions||[];
function norm(t){return t.replace(/\u0643/g,'\u06A9').replace(/\u064A/g,'\u06CC').replace(/[\u064B-\u065F]/g,'').replace(new RegExp(ZWNJ+'{2,}','g'),ZWNJ).replace(/\s+/g,' ').trim();}
const stops=new Set(['و','در','به','از','که','این','را','با','است','آن','یک','برای','تا','ها','های','می','شود']);
function score(kw){const sw=seed.split(/[\s\u200C]+/).filter(w=>!stops.has(w));const kws=kw.split(/[\s\u200C]+/).filter(w=>!stops.has(w));let m=0;sw.forEach(s=>{if(kws.some(k=>k.includes(s)||s.includes(k)))m++;});return Math.min(100,Math.round((sw.length?m/sw.length:0.5)*100)+Math.min(20,kws.length*5));}
function isQ(t){return t.includes('؟')||['چیست','چگونه','چرا','کجا','آیا'].some(q=>t.includes(q));}
const all=new Map();
function add(kw,src){const n=norm(kw);if(n.length<3)return;const key=n.toLowerCase().replace(/\u200C/g,' ');if(key===seed.toLowerCase().replace(/\u200C/g,' '))return;if(!all.has(key))all.set(key,{keyword:n,source:src,relevance:score(n),is_question:isQ(n)});}
base.forEach(k=>add(k,'suggest'));expanded.forEach(k=>add(k,'suggest'));
rel.forEach(k=>add(k,'related'));paa.forEach(k=>add(k,'paa'));
const ideas=Array.from(all.values()).sort((a,b)=>b.relevance-a.relevance).slice(0,200);
return[{json:{discovery_id:discId,callback_url:cbUrl,ideas}}];
